\u8FD8\u8BB0\u5F97\u4E4B\u524D\u7ED8\u5236\u68CB\u76D8\u7684\u4F8B\u5B50\u5417\uFF0C\u4E4B\u524D\u65E0\u8BBA\u662F\u901A\u8FC7CustomPaint\u8FD8\u662F\u81EA\u5B9A\u4E49RenderObject\uFF0C\u90FD\u662F\u5728Flutter\u7684Widget\u6846\u67B6\u6A21\u578B\u4E0B\u8FDB\u884C\u7684\u7ED8\u5236\uFF0C\u5B9E\u9645\u4E0A\uFF0C\u6700\u7EC8\u5230\u5E95\u5C42Flutter\u90FD\u4F1A\u6309\u7167\u4E0A\u8FF0\u7684\u6D41\u7A0B\u53BB\u5B8C\u6210\u7ED8\u5236\uFF0C\u65E2\u7136\u5982\u6B64\uFF0C\u90A3\u4E48\u6211\u4EEC\u4E5F\u53EF\u4EE5\u76F4\u63A5\u5728main\u51FD\u6570\u4E2D\u8C03\u7528\u8FD9\u4E9B\u5E95\u5C42API\u6765\u5B8C\u6210\uFF0C\u4E0B\u9762\u6211\u4EEC\u6F14\u793A\u4E00\u4E0B\u76F4\u63A5\u5728main\u51FD\u6570\u4E2D\u5728\u5C4F\u5E55\u4E2D\u7ED8\u5236\u68CB\u76D8\u3002
