class SliverConstraints extends Constraints { //\u4E3B\u8F74\u65B9\u5411 AxisDirection? axisDirection; //Sliver \u6CBF\u7740\u4E3B\u8F74\u4ECE\u5217\u8868\u7684\u54EA\u4E2A\u65B9\u5411\u63D2\u5165\uFF1F\u679A\u4E3E\u7C7B\u578B\uFF0C\u6B63\u5411\u6216\u53CD\u5411 GrowthDirection? growthDirection; //\u7528\u6237\u6ED1\u52A8\u65B9\u5411 ScrollDirection? userScrollDirection; //\u5F53\u524DSliver\u7406\u8BBA\u4E0A\uFF08\u53EF\u80FD\u4F1A\u56FA\u5B9A\u5728\u9876\u90E8\uFF09\u5DF2\u7ECF\u6ED1\u51FA\u53EF\u89C6\u533A\u57DF\u7684\u603B\u504F\u79FB double? scrollOffset; //\u5F53\u524DSliver\u4E4B\u524D\u7684Sliver\u5360\u636E\u7684\u603B\u9AD8\u5EA6\uFF0C\u56E0\u4E3A\u5217\u8868\u662F\u61D2\u52A0\u8F7D\uFF0C\u5982\u679C\u4E0D\u80FD\u9884\u4F30\u65F6\uFF0C\u8BE5\u503C\u4E3Adouble.infinity double? precedingScrollExtent; //\u4E0A\u4E00\u4E2A sliver \u8986\u76D6\u5F53\u524D sliver \u7684\u5927\u5C0F\uFF0C\u901A\u5E38\u5728 sliver \u662F pinned/floating //\u6216\u8005\u5904\u4E8E\u5217\u8868\u5934\u5C3E\u65F6\u6709\u6548\uFF0C\u6211\u4EEC\u5728\u540E\u9762\u7684\u5C0F\u8282\u4E2D\u4F1A\u6709\u76F8\u5173\u7684\u4F8B\u5B50\u3002 double? overlap; //\u5F53\u524DSliver\u5728Viewport\u4E2D\u7684\u6700\u5927\u53EF\u4EE5\u7ED8\u5236\u7684\u533A\u57DF\u3002 //\u7ED8\u5236\u5982\u679C\u8D85\u8FC7\u8BE5\u533A\u57DF\u4F1A\u6BD4\u8F83\u4F4E\u6548\uFF08\u56E0\u4E3A\u4E0D\u4F1A\u663E\u793A\uFF09 double? remainingPaintExtent; //\u7EB5\u8F74\u7684\u957F\u5EA6\uFF1B\u5982\u679C\u5217\u8868\u6EDA\u52A8\u65B9\u5411\u662F\u5782\u76F4\u65B9\u5411\uFF0C\u5219\u8868\u793A\u5217\u8868\u5BBD\u5EA6\u3002 double? crossAxisExtent; //\u7EB5\u8F74\u65B9\u5411 AxisDirection? crossAxisDirection; //Viewport\u5728\u4E3B\u8F74\u65B9\u5411\u7684\u957F\u5EA6\uFF1B\u5982\u679C\u5217\u8868\u6EDA\u52A8\u65B9\u5411\u662F\u5782\u76F4\u65B9\u5411\uFF0C\u5219\u8868\u793A\u5217\u8868\u9AD8\u5EA6\u3002 double? viewportMainAxisExtent; //Viewport \u9884\u6E32\u67D3\u533A\u57DF\u7684\u8D77\u70B9[-Viewport.cacheExtent, 0] double? cacheOrigin; //Viewport\u52A0\u8F7D\u533A\u57DF\u7684\u957F\u5EA6\uFF0C\u8303\u56F4: //[viewportMainAxisExtent,viewportMainAxisExtent + Viewport.cacheExtent*2] double? remainingCacheExtent;
}
