class CartModel extends ChangeNotifier { // \u7528\u4E8E\u4FDD\u5B58\u8D2D\u7269\u8F66\u4E2D\u5546\u54C1\u5217\u8868 final List<Item> _items = []; // \u7981\u6B62\u6539\u53D8\u8D2D\u7269\u8F66\u91CC\u7684\u5546\u54C1\u4FE1\u606F UnmodifiableListView<Item> get items => UnmodifiableListView(_items); // \u8D2D\u7269\u8F66\u4E2D\u5546\u54C1\u7684\u603B\u4EF7 double get totalPrice => _items.fold(0, (value, item) => value + item.count * item.price); // \u5C06 [item] \u6DFB\u52A0\u5230\u8D2D\u7269\u8F66\u3002\u8FD9\u662F\u552F\u4E00\u4E00\u79CD\u80FD\u4ECE\u5916\u90E8\u6539\u53D8\u8D2D\u7269\u8F66\u7684\u65B9\u6CD5\u3002 void add(Item item) { _items.add(item); // \u901A\u77E5\u76D1\u542C\u5668\uFF08\u8BA2\u9605\u8005\uFF09\uFF0C\u91CD\u65B0\u6784\u5EFAInheritedProvider\uFF0C \u66F4\u65B0\u72B6\u6001\u3002 notifyListeners(); }
}
